// Fetch verified common tokens from Supabase
const dbTokens = await $helpers.httpRequest({
  method: 'GET',
  url: 'https://ymwjfvtqtgtfqfiojsyx.supabase.co/rest/v1/common_tokens?select=symbol,mint',
  headers: {
    'apikey': 'sb_publishable_nI6zclBG_CYamJP5PjgXoA_dTzFBHWB',
    'Authorization': 'Bearer sb_publishable_nI6zclBG_CYamJP5PjgXoA_dTzFBHWB'
  }
});

// Build token map: symbol → mint
const tokenMap = {};
for (const token of dbTokens) {
  if (token.symbol && token.mint) tokenMap[token.symbol] = token.mint;
}

// Build live MEXC price map
const mexcPriceMap = {};
for (const item of $input.all()) {
  const t = item.json;
  if (typeof t.symbol === 'string' && t.symbol.endsWith('USDT')) {
    mexcPriceMap[t.symbol.slice(0, -4)] = parseFloat(t.price);
  }
}

// Intersect: tokens present on both exchanges right now
const result = [];
for (const [sym, mint] of Object.entries(tokenMap)) {
  if (mexcPriceMap[sym] !== undefined) {
    result.push({ symbol: sym, mint, mexcPrice: mexcPriceMap[sym] });
  }
}

return result.map(t => ({ json: t }));

const tokens = $input.all();
if (!tokens.length) return [];

const mints = tokens.map(t => t.json.mint);

// Split into batches of 50 (price/v3 limit)
const batches = [];
for (let i = 0; i < mints.length; i += 50) {
  batches.push(mints.slice(i, i + 50).join(','));
}

// Fetch all batches in parallel
const results = await Promise.all(batches.map(ids =>
  $helpers.httpRequest({
    method: 'GET',
    url: `https://api.jup.ag/price/v3?ids=${ids}`,
    headers: { 'x-api-key': 'YOUR_JUPITER_API_KEY' }
  })
));

// Merge into a single price map: mint → usdPrice
const priceMap = {};
for (const batch of results) {
  for (const [mint, data] of Object.entries(batch)) {
    if (data && data.usdPrice != null) {
      priceMap[mint] = parseFloat(data.usdPrice);
    }
  }
}

// Return enriched token items (only those with a Jupiter price)
return tokens
  .filter(t => priceMap[t.json.mint] != null)
  .map(t => ({
    json: {
      symbol: t.json.symbol,
      mint: t.json.mint,
      mexcPrice: t.json.mexcPrice,
      jupPrice: priceMap[t.json.mint]
    }
  }));

const items = $input.all();
const spreads = [];
const timestamp = new Date().toISOString();

for (const item of items) {
  const { symbol, mint, mexcPrice, jupPrice } = item.json;
  if (!jupPrice || !mexcPrice || isNaN(jupPrice) || isNaN(mexcPrice)) continue;

  const spreadPct = ((mexcPrice - jupPrice) / jupPrice) * 100;
  const absSpread = Math.abs(spreadPct);

  if (absSpread >= 5) {
    spreads.push({
      symbol, mint,
      mexc_price: mexcPrice,
      jup_price: jupPrice,
      spread_pct: parseFloat(spreadPct.toFixed(4)),
      abs_spread_pct: parseFloat(absSpread.toFixed(4)),
      direction: spreadPct > 0 ? 'Buy JUP -> Sell MEXC' : 'Buy MEXC -> Sell JUP'
    });
  }
}

spreads.sort((a, b) => b.abs_spread_pct - a.abs_spread_pct);
return [{ json: { spreads, count: spreads.length, tokens_compared: items.length, timestamp } }];
